            steps += 1
        if len(set(password)) != len(password):
            steps += 1
        if len(password) < 6 or len(password) > 20:
            steps += 1
        if not any(c.islower() for c in password) or not any(c.isupper() for c in password) or not any(c.isdigit() for c in password):
            steps += 1
    return steps

